import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DATA_PATH = path.join(__dirname, '..', 'src', 'data', 'juz1.json');

// Strip HTML-fetch artifacts and normalise whitespace.
function clean(s) {
  return s
    // "ইyz" + variants → "ইয" (Latin y/z slipped in from source HTML)
    .replace(/ইyzا/g, 'ইযা')
    .replace(/ইyzা/g, 'ইযা')
    .replace(/ইyz/g, 'ইয')
    // Stray Arabic letters that bled into Bangla text
    .replace(/[؀-ۿ]/g, '')
    // Common mid-word splits from HTML rendering
    .replace(/ছু ম্মা/g, 'ছুম্মা')
    .replace(/দূ না/g, 'দূনা')
    .replace(/দূ ন/g, 'দূন')
    .replace(/খা-লিদূ ن/g, 'খা-লিদূন')
    .replace(/খা-লিদূ ন/g, 'খা-লিদূন')
    // Multiple spaces → single
    .replace(/\s+/g, ' ')
    .trim();
}

