const raw = fs.readFileSync(DATA_PATH, 'utf8');
const ayahs = JSON.parse(raw);

let applied = 0;
let skipped = 0;
for (const m of ENTRIES) {
  const ayah = ayahs.find(a => a.sno === m.sno && a.n === m.n);
  if (!ayah) {
    console.warn(`  ! No ayah for sno=${m.sno} n=${m.n}`);
    skipped++;
    continue;
  }
  ayah.bnt = clean(m.bnt);
  ayah.bntAuto = false;
  ayah.bntSource = 'alqurans.com';
  applied++;
}

fs.writeFileSync(DATA_PATH, JSON.stringify(ayahs, null, 0) + '\n', 'utf8');
console.log(`Applied ${applied} entries (${skipped} skipped). Source: alqurans.com`);
console.log('\nFirst few:');
for (const sample of [{sno:1,n:1}, {sno:2,n:1}, {sno:2,n:30}, {sno:2,n:67}, {sno:2,n:141}]) {
  const a = ayahs.find(x => x.sno === sample.sno && x.n === sample.n);
  if (a) console.log(`  ${a.se} ${a.sno}:${a.n}  ${a.bnt}`);
}
